SELECT study_name, principal_investigator
FROM studies
WHERE study_status = 'Active';

SELECT study_id, COUNT(*) AS total_key_findings
FROM study_key_findings
GROUP BY study_id;

SELECT finding_text, finding_date, finding_category
FROM study_key_findings
WHERE finding_category = 'safety' AND finding_date >= '2023-05-01';

SELECT s.study_name, cg.group_name, s.study_status
FROM studies s
INNER JOIN comparison_groups cg ON s.comparison_groups = cg.group_id;
